6	  const days = range === "month" ? 30 : 7;
7	
8	  const habits = store.habits.filter((h: any) => h.isActive).map((h: any) => {
9	    const logs = store.habitLogs
10	      .filter((l: any) => l.habitId === h.id)
11	      .map((l: any) => ({ date: l.date, completed: l.completed }));
