1	import { NextRequest, NextResponse } from "next/server";
2	import { store, createGoal, getGoalById, deleteGoal, createGoalLog, calculateProgress, calculateDaysRemaining } from "@/lib/store";
3	
4	const todayStr = () => new Date().toISOString().split("T")[0];
5	
6	function enrichGoal(g: any) {
7	  const goal = { ...g };
8	  const progress = calculateProgress(goal);
9	  const daysRemaining = calculateDaysRemaining(goal.deadline);
10	
