import { PrismaClient } from "@prisma/client";

const globalForPrisma = globalThis as unknown as { prisma: PrismaClient | undefined };

export const prisma = globalForPrisma.prisma ?? new PrismaClient();

if (process.env.NODE_ENV !== "production") globalForPrisma.prisma = prisma;

import { PrismaClient } from "@prisma/client";

const prisma = new PrismaClient();

async function main() {
  // ── User ──
  const user = await prisma.user.upsert({
    where: { id: "demo" },
    update: {},
    create: {
      id: "demo",
      email: "demo@tianzi.com",
      name: "Demo User",
    },
  });

  // ── Domains ──
  const domainData = [
    { name: "健身", icon: "dumbbell", color: "#ef4444", sortOrder: 1 },
    { name: "读书", icon: "book-open", color: "#3b82f6", sortOrder: 2 },
    { name: "变美", icon: "sparkles", color: "#ec4899", sortOrder: 3 },
    { name: "工作", icon: "briefcase", color: "#f59e0b", sortOrder: 4 },
    { name: "学习", icon: "graduation-cap", color: "#10b981", sortOrder: 5 },
    { name: "商业思维", icon: "lightbulb", color: "#8b5cf6", sortOrder: 6 },
    { name: "视野", icon: "globe", color: "#06b6d4", sortOrder: 7 },
    { name: "生活习惯", icon: "calendar-check", color: "#f97316", sortOrder: 8 },
    { name: "未分类", icon: "folder", color: "#6b7280", sortOrder: 99, isPreset: false },
  ];

  for (const d of domainData) {
    await prisma.domain.upsert({
      where: { id: d.name },
      update: {},
      create: {
        id: d.name,
        name: d.name,
        icon: d.icon,
        color: d.color,
        sortOrder: d.sortOrder,
        isPreset: d.isPreset ?? true,
      },
    });
  }

  // ── Example Habits ──
  const exampleHabits = [
    {
      id: "habit-morning-run",
      userId: user.id,
      domainId: "健身",
      title: "晨跑 30 分钟",
      description: "公园慢跑，心率保持在130-150",
      frequency: "daily",
      targetValue: 30,
      unit: "分钟",
    },
    {
      id: "habit-reading",
      userId: user.id,
      domainId: "读书",
      title: "阅读 30 分钟",
      description: "纸质书优先，做简短笔记",
      frequency: "daily",
      targetValue: 30,
      unit: "分钟",
    },
  ];

  for (const h of exampleHabits) {
    await prisma.habit.upsert({
      where: { id: h.id },
      update: {},
      create: h,
    });
  }

  // ── Example Goal ──
  await prisma.goal.upsert({
    where: { id: "goal-running" },
    update: {},
    create: {
      id: "goal-running",
      userId: user.id,
      title: "3 个月跑完第一个 10 公里",
      description: "从每天 2 公里起步，逐步增加到 10 公里",
      startValue: 2,
      targetValue: 10,
      currentValue: 2,
      unit: "公里",
      linkedHabitIds: ["habit-morning-run"],
      deadline: new Date("2026-08-12"),
    },
  });

  console.log("Seed completed successfully");
}

main()
  .catch((e) => {
    console.error("Seed failed:", e);
    process.exit(1);
  })
  .finally(async () => {
    await prisma.$disconnect();
  });

// In-memory store removed. Data now lives in PostgreSQL via Prisma.
// This file only contains type definitions and pure computation helpers.

export interface Goal {
  id: string;
  userId: string;
  title: string;
  description: string | null;
  startValue: number;
  targetValue: number;
  currentValue: number;
  unit: string;
  deadline: string | null;
  linkedHabitIds: string[];
  isArchived: boolean;
  createdAt: string;
  updatedAt: string;
}

export interface GoalLog {
  id: string;
  goalId: string;
  userId: string;
  previousValue: number;
  newValue: number;
  delta: number;
  note: string | null;
  createdAt: string;
}

// ── Computation helpers ──

export function calculateProgress(startValue: number, targetValue: number, currentValue: number): number {
  if (targetValue === startValue) return 0;
  if (targetValue > startValue) {
    // Positive direction: e.g. increase running distance
    return Math.min(Math.max((currentValue - startValue) / (targetValue - startValue), 0), 1);
  }
  // Negative direction: e.g. lose weight
  return Math.min(Math.max((startValue - currentValue) / (startValue - targetValue), 0), 1);
}

export function calculateDaysRemaining(deadline: string | null): number | null {
  if (!deadline) return null;
  const now = new Date();
  const deadlineDate = new Date(deadline);
  const diff = deadlineDate.getTime() - now.getTime();
  return Math.ceil(diff / (1000 * 60 * 60 * 24));
}

