    : [];

  const linkedHabitResults = linkedHabits.map((h: any) => {
    const log = todayLogs.find((l: any) => l.habitId === h.id);
    return { id: h.id, title: h.title, completed: log?.completed || false };
  });

  return {
    ...g,
    linkedHabits: linkedHabitResults,
    progress,
    daysRemaining,
    linkedHabitsCompleted: linkedHabitResults.filter((h: any) => h.completed).length,
    linkedHabitsTotal: linkedHabitResults.length,
  };
}

export async function GET(req: NextRequest) {
  const includeArchived = req.nextUrl.searchParams.get("includeArchived") === "true";

  const goals = await prisma.goal.findMany({
    where: { userId: "demo", ...(includeArchived ? {} : { isArchived: false }) },
  });

  const enriched = await Promise.all(goals.map(enrichGoal));
  return NextResponse.json(enriched);
}

export async function POST(req: NextRequest) {
  const body = await req.json();

  if (!body.title || typeof body.title !== "string" || body.title.length < 1 || body.title.length > 50) {
    return NextResponse.json({ error: "Title is required (1-50 characters)" }, { status: 400 });
  }
  if (body.startValue === undefined || body.targetValue === undefined) {
    return NextResponse.json({ error: "startValue and targetValue are required" }, { status: 400 });
  }
  if (body.targetValue === body.startValue) {
    return NextResponse.json({ error: "targetValue must differ from startValue" }, { status: 400 });
  }
  if (!body.unit || typeof body.unit !== "string") {
    return NextResponse.json({ error: "unit is required" }, { status: 400 });
  }

  const goal = await prisma.goal.create({
    data: {
      userId: "demo",
      title: body.title,
      description: body.description || null,
      startValue: body.startValue,
      targetValue: body.targetValue,
      currentValue: body.currentValue ?? body.startValue,
      unit: body.unit,
      deadline: body.deadline ? new Date(body.deadline + "T00:00:00Z") : null,
      linkedHabitIds: body.linkedHabitIds || [],
    },
  });

  // Create initial GoalLog
  await prisma.goalLog.create({
    data: {
      goalId: goal.id,
      userId: "demo",
      previousValue: body.startValue,
      newValue: goal.currentValue,
      delta: goal.currentValue - body.startValue,
      note: "目标创建",
    },
  });

  return NextResponse.json(goal, { status: 201 });
}

export async function PUT(req: NextRequest) {
  const { id, note, ...updates } = await req.json();

  const existing = await prisma.goal.findUnique({ where: { id } });
  if (!existing) {
    return NextResponse.json({ error: "Not found" }, { status: 404 });
  }

  if (Object.keys(updates).length === 0) {
    return NextResponse.json({ error: "No changes detected" }, { status: 400 });
  }

  // Auto-create GoalLog when currentValue changes
  let updateData: any = { ...updates };
  if (updates.currentValue !== undefined && updates.currentValue !== existing.currentValue) {
    const previousValue = existing.currentValue;
    const delta = updates.currentValue - previousValue;
    await prisma.goalLog.create({
      data: {
        goalId: id,
        userId: "demo",
        previousValue,
        newValue: updates.currentValue,
        delta,
        note: note || null,
      },
    });

    // Convert deadline if present
    if (updateData.deadline) {
      updateData.deadline = new Date(updateData.deadline + "T00:00:00Z");
    }
  }

  const goal = await prisma.goal.update({
    where: { id },
    data: updateData,
  });

  return NextResponse.json(goal);
}

export async function DELETE(req: NextRequest) {
  const { id } = await req.json();

  const existing = await prisma.goal.findUnique({ where: { id } });
  if (!existing) {
    return NextResponse.json({ error: "Not found" }, { status: 404 });
  }

  await prisma.goal.delete({ where: { id } });
  return NextResponse.json({ ok: true });
}

