import { NextRequest, NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";
import { getAIRecommendation } from "@/lib/claude";

export async function POST(req: NextRequest) {
  const { type, data, prompt } = await req.json();

  try {
    if (type === "weekly") {
      const habits = await prisma.habit.findMany({
        where: { userId: "demo", isActive: true },
      });
      const allLogs = await prisma.habitLog.findMany({
        where: { userId: "demo" },
      });

      const today = new Date();
      const logs: any[] = [];
      for (let i = 6; i >= 0; i--) {
        const d = new Date(today);
        d.setDate(d.getDate() - i);
        const dateStr = d.toISOString().split("T")[0];
        const dayLogs = allLogs.filter(
          (l) => l.date.toISOString().split("T")[0] === dateStr
        );
        logs.push({ date: dateStr, completed: dayLogs.filter((l) => l.completed).length, total: dayLogs.length });
      }

      const message = `作为个人成长教练，根据以下本周数据给一段简短的洞察（200字以内）：
完成情况: ${logs.map((l) => `${l.date}: ${l.completed}/${l.total}`).join(", ")}
活跃习惯: ${habits.map((h) => h.title).join("、")}
指出1-2个趋势，给出1条具体改进建议。语气像帝王侍读。`;

      const text = await getAIRecommendation(message);
      return NextResponse.json({ text });
    }

    if (type === "review") {
      const message = `用户刚做了今日复盘：评分${data.score}/5，总结："${data.summary}"，亮点："${data.highlight}"，不足："${data.lowlight}"。请用帝王侍读的语气给一段鼓励+建议（100字以内）。`;
      const text = await getAIRecommendation(message);
      return NextResponse.json({ text });
    }

    if (type === "generate-habits") {
      const message = `用户描述了以下目标："${prompt}"。请帮用户拆解成3-5个具体的每日习惯，每个习惯格式为：- [领域] 习惯名称：具体描述（目标值+单位）。直接给列表，不要多余的话。`;
      const text = await getAIRecommendation(message);
      return NextResponse.json({ text });
    }

    if (type === "daily-summary") {
      const habits = await prisma.habit.findMany({
        where: { userId: "demo", isActive: true },
      });
      const allLogs = await prisma.habitLog.findMany({
        where: { userId: "demo" },
      });

      const todayStr = new Date().toISOString().split("T")[0];
      const todayLogs = allLogs.filter((l) => l.date.toISOString().split("T")[0] === todayStr);
      const completedCount = todayLogs.filter((l) => l.completed).length;
      const totalCount = habits.length;
      const completionRate = totalCount > 0 ? Math.round((completedCount / totalCount) * 100) : 0;

      // 连续天数
      let streak = 0;
      const now = new Date();
      for (let i = 0; i < 365; i++) {
        const d = new Date(now);
        d.setDate(d.getDate() - i);
        const ds = d.toISOString().split("T")[0];
        const dayCompleted = allLogs.filter((l) => l.date.toISOString().split("T")[0] === ds && l.completed).length;
        if (dayCompleted > 0) streak++;
        else break;
      }

      // 昨日复盘
      const yesterday = new Date(now);
      yesterday.setDate(yesterday.getDate() - 1);
      const yesterdayStr = yesterday.toISOString().split("T")[0];
      const yesterdayReview = await prisma.dailyReview.findUnique({
        where: { userId_date: { userId: "demo", date: new Date(yesterdayStr + "T00:00:00Z") } },
      });

      const message = `用户今日打卡情况：完成 ${completedCount}/${totalCount} 项习惯，完成率 ${completionRate}%，连续 ${streak} 天。${yesterdayReview ? `昨日复盘："${yesterdayReview.summary}"` : ""}请用帝王侍读的口吻，给一段温暖、简洁的今日小结（80-120字），既肯定成就又温和提醒不足。`;

      const text = await getAIRecommendation(message);
      return NextResponse.json({ text });
    }

    if (type === "daily-goals") {
      const habits = await prisma.habit.findMany({
        where: { userId: "demo", isActive: true },
      });
      const allLogs = await prisma.habitLog.findMany({
        where: { userId: "demo" },
      });

      const now = new Date();

      // 近14天各习惯完成率
      const habitStats = habits.map((h) => {
        let completed = 0;
        let total = 0;
        for (let i = 1; i <= 14; i++) {
          const d = new Date(now);
          d.setDate(d.getDate() - i);
          const ds = d.toISOString().split("T")[0];
          const log = allLogs.find((l) => l.habitId === h.id && l.date.toISOString().split("T")[0] === ds);
          total++;
          if (log?.completed) completed++;
        }
        return { title: h.title, completionRate: Math.round((completed / total) * 100), streak: 0 };
      });

      // 查断档
      habitStats.forEach((hs: any) => {
        let s = 0;
        for (let i = 1; i <= 14; i++) {
          const d = new Date(now);
          d.setDate(d.getDate() - i);
          const ds = d.toISOString().split("T")[0];
          const log = allLogs.find(
            (l) =>
              l.habitId === habits.find((h) => h.title === hs.title)?.id &&
              l.date.toISOString().split("T")[0] === ds
          );
          if (!log?.completed) break;
          s++;
        }
        hs.streak = s;
      });

      const message = `用户近14天各习惯完成率：${habitStats.map((hs: any) => `${hs.title}(${hs.completionRate}%)`).join("，")}。连续未做的习惯：${habitStats.filter((hs: any) => hs.streak === 0).map((hs: any) => hs.title).join("、") || "无"}。请基于以上数据，推荐2-3条明日具体可执行的行动建议。返回 JSON 数组格式：[{"title":"...","detail":"...","reason":"..."}]，不要 markdown 包裹，只返回纯 JSON。`;

      const text = await getAIRecommendation(message);
      try {
        const goals = JSON.parse(text);
        return NextResponse.json({ goals: Array.isArray(goals) ? goals : [] });
      } catch {
        return NextResponse.json({ goals: [] });
      }
    }

    return NextResponse.json({ error: "Unknown type" }, { status: 400 });
  } catch (err) {
    // If API is not configured, return a fallback message
    return NextResponse.json({
      text: type === "weekly"
        ? "本周数据已汇总。完成率最高的领域是健身上午时段，建议将重要习惯安排在精力充沛的早晨。连续3天以上达标的习惯会形成惯性，再坚持一下。"
        : type === "review"
        ? "每日三省，便是精进。今日无论得失，皆是明日之基石。坚持复盘，自见成效。"
        : "根据你的目标，建议从每天25分钟的微习惯开始，不求多但求持续。三周后自然成习惯。",
    });
  }
}

import { NextRequest, NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";
import { calculateProgress, calculateDaysRemaining } from "@/lib/store";
import { getAIRecommendation } from "@/lib/claude";

export async function GET(req: NextRequest) {
  const type = req.nextUrl.searchParams.get("type");

  try {
    if (type === "progress") {
      return await handleProgressAnalysis(req);
    }
    if (type === "recommend") {
      return await handleRecommendation();
    }
    return NextResponse.json({ error: "Unknown type" }, { status: 400 });
  } catch (err) {
    return NextResponse.json({
      trend: "unknown",
      assessment: "数据不足，继续记录即可看到趋势",
      canMeetDeadline: null,
      suggestions: ["保持当前节奏", "定期更新数值"],
      adjustDeadline: false,
    });
  }
}

async function handleProgressAnalysis(req: NextRequest) {
  const goalId = req.nextUrl.searchParams.get("goalId");
  if (!goalId) {
    return NextResponse.json({ error: "goalId is required" }, { status: 400 });
  }

  const goal = await prisma.goal.findUnique({ where: { id: goalId } });
  if (!goal) {
    return NextResponse.json({ error: "Goal not found" }, { status: 404 });
  }

  const daysRemaining = goal.deadline
    ? calculateDaysRemaining(goal.deadline.toISOString().split("T")[0])
    : null;
  const progress = calculateProgress(goal.startValue, goal.targetValue, goal.currentValue);

  // Logs sorted ascending
  const logs = await prisma.goalLog.findMany({
    where: { goalId },
    orderBy: { createdAt: "asc" },
  });

  const recentLogsStr = logs.slice(-7).map((l) => {
    const sign = l.delta > 0 ? "+" : "";
    const notePart = l.note ? ` - ${l.note}` : "";
    return `${l.createdAt}: ${l.previousValue} → ${l.newValue} (${sign}${l.delta})${notePart}`;
  }).join("\n");

  // Linked habits 14-day completion
  const now = new Date();
  const allLogs = await prisma.habitLog.findMany({
    where: { userId: "demo" },
  });
  const linkedHabits = (goal.linkedHabitIds || []).length > 0
    ? await prisma.habit.findMany({ where: { id: { in: goal.linkedHabitIds } } })
    : [];

  const linkedHabitsInfo = linkedHabits.map((habit) => {
    let completed = 0;
    let total = 0;
    for (let i = 1; i <= 14; i++) {
      const d = new Date(now);
      d.setDate(d.getDate() - i);
      const ds = d.toISOString().split("T")[0];
      const log = allLogs.find((l) => l.habitId === habit.id && l.date.toISOString().split("T")[0] === ds);
      total++;
      if (log?.completed) completed++;
    }
    return `${habit.title}: ${total > 0 ? Math.round((completed / total) * 100) : 0}%`;
  }).filter(Boolean).join("\n");

  const direction = goal.targetValue > goal.startValue ? "增加型" : "减少型";

  const prompt = `作为帝王侍读，分析以下目标进展：

目标：${goal.title}
${direction}目标
起始值：${goal.startValue}${goal.unit} → 目标值：${goal.targetValue}${goal.unit}
当前值：${goal.currentValue}${goal.unit}（进度 ${Math.round(progress * 100)}%）
${goal.deadline ? `截止日期：${goal.deadline.toISOString().split("T")[0]}\n剩余天数：${daysRemaining}` : "截止日期：无"}
${goal.description ? `描述：${goal.description}` : ""}

历史记录（最近 7 条）：
${recentLogsStr || "暂无记录"}

关联习惯近 14 天完成率：
${linkedHabitsInfo || "无关联习惯"}

请给出：
1. 趋势判断（按当前速度能否按时达标）
2. 1-2 条具体调整建议
3. 是否需要调整目标值或截止日期

返回 JSON：{"trend": "accelerating|on-track|slowing|stuck|unknown", "assessment": "一句话判断", "canMeetDeadline": true|false, "suggestions": ["建议1", "建议2"], "adjustDeadline": true|false}`;

  const text = await getAIRecommendation(prompt);
  try {
    const result = JSON.parse(text);
    return NextResponse.json({
      trend: result.trend || "unknown",
      assessment: result.assessment || "数据不足，继续记录即可看到趋势",
      canMeetDeadline: result.canMeetDeadline ?? null,
      suggestions: Array.isArray(result.suggestions) ? result.suggestions : ["保持当前节奏", "定期更新数值"],
      adjustDeadline: !!result.adjustDeadline,
    });
  } catch {
    return NextResponse.json({
      trend: "unknown",
      assessment: "数据不足，继续记录即可看到趋势",
      canMeetDeadline: null,
      suggestions: ["保持当前节奏", "定期更新数值"],
      adjustDeadline: false,
    });
  }
}

async function handleRecommendation() {
  const now = new Date();

  // Active habits with 14-day completion
  const activeHabits = await prisma.habit.findMany({
    where: { userId: "demo", isActive: true },
  });
  const allLogs = await prisma.habitLog.findMany({
    where: { userId: "demo" },
  });

  const habitStats = activeHabits.map((h) => {
    let completed = 0;
    let total = 0;
    for (let i = 1; i <= 14; i++) {
      const d = new Date(now);
      d.setDate(d.getDate() - i);
      const ds = d.toISOString().split("T")[0];
      const log = allLogs.find((l) => l.habitId === h.id && l.date.toISOString().split("T")[0] === ds);
      total++;
      if (log?.completed) completed++;
    }
    return {
      title: h.title,
      domainId: h.domainId || "",
      completionRate: total > 0 ? Math.round((completed / total) * 100) : 0,
    };
  });

  const existingGoals = await prisma.goal.findMany({
    where: { userId: "demo" },
    select: { title: true },
  });
  const existingGoalTitles = existingGoals.map((g) => g.title);

  const habitsStr = habitStats.map((h) => `${h.title} (${h.domainId}): ${h.completionRate}%`).join("\n");
  const existingStr = existingGoalTitles.join("、") || "无";

  const prompt = `用户当前有以下习惯（近 14 天完成率）：
${habitsStr}

已有目标：${existingStr}

请推荐 2-3 个适合用户的新目标，每个目标应符合用户的习惯组合，目标值要具体可量化。
格式：严格返回 JSON 数组，不要任何 markdown 包裹：
[{"title":"目标名称","description":"简短理由","suggestedStartValue":0,"suggestedTargetValue":0,"unit":"单位","suggestedDeadlineDays":30}]`;

  try {
    const text = await getAIRecommendation(prompt);
    const recommendations = JSON.parse(text);
    return NextResponse.json(Array.isArray(recommendations) ? recommendations : []);
  } catch {
    return NextResponse.json([]);
  }
}

